            'projection.pessimistic.summary' => ['en' => 'An early 2040 stress horizon at the end of the IPCC near-term window under SSP5-8.5, with locally dangerous humid heat already observed and protection gaps unresolved.', 'it' => 'Un orizzonte anticipato di stress al 2040, fine della finestra IPCC di breve termine con SSP5-8.5, con caldo umido localmente pericoloso già osservato e divari di protezione irrisolti.', 'fr' => 'Un horizon précoce de stress en 2040, fin de la fenêtre de court terme du GIEC sous SSP5-8.5, avec une chaleur humide localement dangereuse déjà observée et des lacunes de protection.', 'de' => 'Ein früher Stresshorizont 2040 am Ende des IPCC-Nahzeitfensters unter SSP5-8.5, bei bereits lokal beobachteter gefährlicher feuchter Hitze und ungelösten Schutzlücken.', 'es' => 'Un horizonte temprano de estrés en 2040, final de la ventana de corto plazo del IPCC bajo SSP5-8.5, con calor húmedo localmente peligroso ya observado y brechas de protección.', 'nl' => 'Een vroege stresshorizon in 2040 aan het einde van het IPCC-nabije-termijnvenster onder SSP5-8.5, met lokaal al waargenomen gevaarlijke vochtige hitte en onopgeloste beschermingskloven.', 'sv' => 'En tidig stresshorisont 2040 vid slutet av IPCC:s närtidsfönster under SSP5-8.5, med lokalt farlig fuktig hetta redan observerad och kvarstående skyddsgap.', 'pl' => 'Wczesny horyzont stresu w 2040 r., na końcu krótkoterminowego okna IPCC przy SSP5-8.5, z lokalnie obserwowanym niebezpiecznym wilgotnym upałem i nierozwiązanymi lukami ochrony.'],
            'chart.projection.title' => ['en' => 'Assessed climate windows and heat-risk horizons', 'it' => 'Finestre climatiche valutate e orizzonti di rischio caldo', 'fr' => 'Fenêtres climatiques évaluées et horizons de risque thermique', 'de' => 'Bewertete Klimazeiträume und Hitzerisiko-Horizonte', 'es' => 'Ventanas climáticas evaluadas y horizontes de riesgo térmico', 'nl' => 'Beoordeelde klimaatvensters en hitterisicohorizonten', 'sv' => 'Bedömda klimatfönster och värmeriskhorisonter', 'pl' => 'Ocenione okna klimatyczne i horyzonty ryzyka upału'],
            'chart.projection.description' => ['en' => 'The observed 2025 anomaly followed by IPCC central estimates at the midpoints of the near-, mid- and long-term assessment windows.', 'it' => 'L’anomalia osservata nel 2025 seguita dalle stime centrali IPCC ai punti medi delle finestre di breve, medio e lungo termine.', 'fr' => 'L’anomalie observée en 2025 suivie des estimations centrales du GIEC aux milieux des fenêtres de court, moyen et long terme.', 'de' => 'Die beobachtete Anomalie 2025, gefolgt von IPCC-Zentralschätzungen an den Mittelpunkten der Nah-, Mittel- und Langfristfenster.', 'es' => 'La anomalía observada en 2025 seguida de las estimaciones centrales del IPCC en los puntos medios de las ventanas de corto, medio y largo plazo.', 'nl' => 'De waargenomen anomalie van 2025 gevolgd door centrale IPCC-schattingen op de middelpunten van de korte, middellange en lange termijn.', 'sv' => 'Den observerade anomalin 2025 följd av IPCC:s centrala skattningar vid mittpunkterna för nära, medellång och lång sikt.', 'pl' => 'Obserwowana anomalia z 2025 r., a następnie centralne szacunki IPCC w środkach okien krótkiego, średniego i długiego terminu.'],
            'chart.projection.reasoning' => ['en' => 'WMO observed 1.44°C in 2025 relative to 1850–1900. IPCC AR6 central estimates are plotted at representative midpoints: 2030 for 2021–2040, 2050 for 2041–2060 and 2090 for 2081–2100. Values are SSP1-1.9: 1.5/1.6/1.4°C; SSP2-4.5: 1.5/2.0/2.7°C; SSP5-8.5: 1.6/2.4/4.4°C. No annual interpolation is used. The editorial target dates 2040, 2050 and 2100 are assessment boundaries, not wet-bulb, heat-index or survivability threshold dates.', 'it' => 'WMO ha osservato 1,44°C nel 2025 rispetto al 1850–1900. Le stime centrali IPCC AR6 sono poste su punti medi rappresentativi: 2030 per 2021–2040, 2050 per 2041–2060 e 2090 per 2081–2100. Valori: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. Non si usa interpolazione annuale. Le date editoriali 2040, 2050 e 2100 sono confini di valutazione, non date di soglia wet-bulb, heat index o sopravvivenza.', 'fr' => 'La WMO a observé 1,44°C en 2025 par rapport à 1850–1900. Les estimations centrales du GIEC AR6 sont placées aux milieux représentatifs : 2030 pour 2021–2040, 2050 pour 2041–2060 et 2090 pour 2081–2100. Valeurs : SSP1-1.9 1,5/1,6/1,4°C ; SSP2-4.5 1,5/2,0/2,7°C ; SSP5-8.5 1,6/2,4/4,4°C. Aucune interpolation annuelle. Les dates 2040, 2050 et 2100 sont des limites d’évaluation, non des seuils de bulbe humide, indice de chaleur ou survie.', 'de' => 'Die WMO beobachtete 2025 1,44°C gegenüber 1850–1900. IPCC-AR6-Zentralschätzungen werden an repräsentativen Mittelpunkten gezeigt: 2030 für 2021–2040, 2050 für 2041–2060 und 2090 für 2081–2100. Werte: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. Keine jährliche Interpolation. Die redaktionellen Daten 2040, 2050 und 2100 sind Bewertungsgrenzen, keine Feuchtkugel-, Hitzeindex- oder Überlebensschwellen.', 'es' => 'La WMO observó 1,44°C en 2025 respecto a 1850–1900. Las estimaciones centrales del IPCC AR6 se sitúan en puntos medios representativos: 2030 para 2021–2040, 2050 para 2041–2060 y 2090 para 2081–2100. Valores: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. No hay interpolación anual. Las fechas 2040, 2050 y 2100 son límites de evaluación, no umbrales de bulbo húmedo, índice de calor o supervivencia.', 'nl' => 'WMO nam in 2025 1,44°C waar ten opzichte van 1850–1900. Centrale IPCC AR6-schattingen staan op representatieve middelpunten: 2030 voor 2021–2040, 2050 voor 2041–2060 en 2090 voor 2081–2100. Waarden: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. Geen jaarlijkse interpolatie. De data 2040, 2050 en 2100 zijn beoordelingsgrenzen, geen nattebol-, hitte-index- of overlevingsdrempels.', 'sv' => 'WMO observerade 1,44°C år 2025 relativt 1850–1900. IPCC AR6:s centrala skattningar visas vid representativa mittpunkter: 2030 för 2021–2040, 2050 för 2041–2060 och 2090 för 2081–2100. Värden: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. Ingen årsinterpolering. Datumen 2040, 2050 och 2100 är bedömningsgränser, inte våttemperatur-, värmeindex- eller överlevnadströsklar.', 'pl' => 'WMO zaobserwowała 1,44°C w 2025 r. względem 1850–1900. Centralne szacunki IPCC AR6 pokazano w reprezentatywnych środkach: 2030 dla 2021–2040, 2050 dla 2041–2060 i 2090 dla 2081–2100. Wartości: SSP1-1.9 1,5/1,6/1,4°C; SSP2-4.5 1,5/2,0/2,7°C; SSP5-8.5 1,6/2,4/4,4°C. Bez interpolacji rocznej. Daty 2040, 2050 i 2100 są granicami oceny, nie progami mokrego termometru, indeksu ciepła ani przeżycia.'],
            'chart.kpi.title' => ['en' => 'Key heat indicators', 'it' => 'Indicatori chiave del caldo', 'fr' => 'Indicateurs clés de chaleur', 'de' => 'Zentrale Hitzeindikatoren', 'es' => 'Indicadores clave de calor', 'nl' => 'Belangrijkste hitte-indicatoren', 'sv' => 'Viktiga värmeindikatorer', 'pl' => 'Kluczowe wskaźniki upału'],
            'chart.kpi.description' => ['en' => 'Observed indicators kept as separate KPI values because their units and populations differ.', 'it' => 'Indicatori osservati mantenuti come KPI separati perché unità e popolazioni differiscono.', 'fr' => 'Indicateurs observés conservés comme KPI séparés car leurs unités et populations diffèrent.', 'de' => 'Beobachtete Indikatoren werden wegen unterschiedlicher Einheiten und Populationen als getrennte KPI geführt.', 'es' => 'Indicadores observados mantenidos como KPI separados porque sus unidades y poblaciones difieren.', 'nl' => 'Waargenomen indicatoren blijven afzonderlijke KPI’s omdat eenheden en populaties verschillen.', 'sv' => 'Observerade indikatorer hålls som separata KPI-värden eftersom enheter och populationer skiljer sig.', 'pl' => 'Obserwowane wskaźniki są oddzielnymi KPI, ponieważ różnią się jednostkami i populacjami.'],
            'chart.kpi.reasoning' => ['en' => 'All headline values are direct observations: 1.44°C is the WMO 2025 global anomaly; 66 strong-heat-stress days and 23 tropical nights refer to southeastern Europe in summer 2024; more than 175,000 annual heat-related deaths is the WHO European Region average for 2000–2019. Incompatible units are intentionally not plotted on one axis.', 'it' => 'Tutti i valori principali sono osservazioni dirette: 1,44°C è l’anomalia globale WMO 2025; 66 giorni di forte stress termico e 23 notti tropicali riguardano l’Europa sudorientale nell’estate 2024; oltre 175.000 decessi annui legati al caldo è la media 2000–2019 della Regione europea OMS. Le unità incompatibili non sono poste sullo stesso asse.', 'fr' => 'Toutes les valeurs principales sont observées : 1,44°C est l’anomalie mondiale WMO 2025 ; 66 jours de fort stress thermique et 23 nuits tropicales concernent l’Europe du Sud-Est durant l’été 2024 ; plus de 175 000 décès annuels liés à la chaleur est la moyenne 2000–2019 de la Région européenne de l’OMS. Les unités incompatibles ne partagent pas un axe.', 'de' => 'Alle Hauptwerte sind direkte Beobachtungen: 1,44°C ist die globale WMO-Anomalie 2025; 66 Tage mit starkem Hitzestress und 23 Tropennächte beziehen sich auf Südosteuropa im Sommer 2024; mehr als 175.000 jährliche hitzebedingte Todesfälle sind der WHO-Europa-Durchschnitt 2000–2019. Unvereinbare Einheiten werden nicht auf einer Achse dargestellt.', 'es' => 'Todos los valores principales son observaciones directas: 1,44°C es la anomalía mundial WMO 2025; 66 días de fuerte estrés térmico y 23 noches tropicales corresponden al sudeste de Europa en verano de 2024; más de 175.000 muertes anuales por calor es la media 2000–2019 de la Región Europea de la OMS. Las unidades incompatibles no comparten eje.', 'nl' => 'Alle hoofdwaarden zijn directe waarnemingen: 1,44°C is de mondiale WMO-anomalie van 2025; 66 dagen met sterke hittestress en 23 tropische nachten gelden voor Zuidoost-Europa in zomer 2024; meer dan 175.000 jaarlijkse hittegerelateerde sterfgevallen is het WHO-Europa-gemiddelde voor 2000–2019. Onverenigbare eenheden delen geen as.', 'sv' => 'Alla huvudvärden är direkta observationer: 1,44°C är WMO:s globala anomali 2025; 66 dagar med stark värmestress och 23 tropiska nätter gäller sydöstra Europa sommaren 2024; över 175 000 årliga värmerelaterade dödsfall är WHO Europas medel för 2000–2019. Oförenliga enheter delar inte axel.', 'pl' => 'Wszystkie wartości główne są obserwowane: 1,44°C to globalna anomalia WMO z 2025 r.; 66 dni silnego stresu cieplnego i 23 noce tropikalne dotyczą Europy Południowo-Wschodniej latem 2024 r.; ponad 175 000 rocznych zgonów związanych z upałem to średnia WHO dla Europy z lat 2000–2019. Niezgodne jednostki nie dzielą osi.'],
            'chart.anomaly.title' => ['en' => 'Global air-temperature anomaly', 'it' => 'Anomalia globale della temperatura dell’aria', 'fr' => 'Anomalie mondiale de température de l’air', 'de' => 'Globale Lufttemperaturanomalie', 'es' => 'Anomalía global de la temperatura del aire', 'nl' => 'Mondiale luchttemperatuuranomalie', 'sv' => 'Global lufttemperaturanomali', 'pl' => 'Globalna anomalia temperatury powietrza'],
            'chart.anomaly.description' => ['en' => 'Observed annual global mean temperature anomalies relative to 1850–1900.', 'it' => 'Anomalie annuali osservate della temperatura media globale rispetto al 1850–1900.', 'fr' => 'Anomalies annuelles observées de la température moyenne mondiale par rapport à 1850–1900.', 'de' => 'Beobachtete jährliche globale Mitteltemperaturanomalien gegenüber 1850–1900.', 'es' => 'Anomalías anuales observadas de la temperatura media global respecto a 1850–1900.', 'nl' => 'Waargenomen jaarlijkse mondiale gemiddelde temperatuuranomalieën ten opzichte van 1850–1900.', 'sv' => 'Observerade årliga globala medeltemperaturanomalier relativt 1850–1900.', 'pl' => 'Obserwowane roczne anomalie globalnej średniej temperatury względem 1850–1900.'],
            'chart.anomaly.reasoning' => ['en' => 'The 2023, 2024 and 2025 values (1.45°C, 1.55°C and 1.44°C) are direct WMO estimates relative to the 1850–1900 pre-industrial baseline. The line connects annual observations; it does not interpolate missing years or represent UTCI, heat index or wet-bulb temperature.', 'it' => 'I valori 2023, 2024 e 2025 (1,45°C, 1,55°C e 1,44°C) sono stime dirette WMO rispetto alla baseline preindustriale 1850–1900. La linea collega osservazioni annuali; non interpola anni mancanti e non rappresenta UTCI, heat index o temperatura di bulbo umido.', 'fr' => 'Les valeurs 2023, 2024 et 2025 (1,45°C, 1,55°C et 1,44°C) sont des estimations directes de la WMO par rapport à la référence préindustrielle 1850–1900. La ligne relie des observations annuelles ; elle n’interpole pas d’années manquantes et ne représente ni UTCI, indice de chaleur ni température de bulbe humide.', 'de' => 'Die Werte 2023, 2024 und 2025 (1,45°C, 1,55°C und 1,44°C) sind direkte WMO-Schätzungen gegenüber der vorindustriellen Basis 1850–1900. Die Linie verbindet Jahresbeobachtungen; sie interpoliert keine fehlenden Jahre und stellt weder UTCI, Hitzeindex noch Feuchtkugeltemperatur dar.', 'es' => 'Los valores de 2023, 2024 y 2025 (1,45°C, 1,55°C y 1,44°C) son estimaciones directas de la WMO respecto a la base preindustrial 1850–1900. La línea conecta observaciones anuales; no interpola años faltantes ni representa UTCI, índice de calor o temperatura de bulbo húmedo.', 'nl' => 'De waarden voor 2023, 2024 en 2025 (1,45°C, 1,55°C en 1,44°C) zijn directe WMO-schattingen ten opzichte van de pre-industriële basis 1850–1900. De lijn verbindt jaarwaarnemingen; zij interpoleert geen ontbrekende jaren en is geen UTCI, hitte-index of natteboltemperatuur.', 'sv' => 'Värdena 2023, 2024 och 2025 (1,45°C, 1,55°C och 1,44°C) är direkta WMO-skattningar relativt den förindustriella baslinjen 1850–1900. Linjen binder samman årsobservationer; den interpolerar inte saknade år och avser inte UTCI, värmeindex eller våttemperatur.', 'pl' => 'Wartości z lat 2023, 2024 i 2025 (1,45°C, 1,55°C i 1,44°C) są bezpośrednimi szacunkami WMO względem bazy przedindustrialnej 1850–1900. Linia łączy obserwacje roczne; nie interpoluje brakujących lat i nie przedstawia UTCI, indeksu ciepła ani temperatury mokrego termometru.'],
            'chart.tropical_share.title' => ['en' => 'European area with tropical nights', 'it' => 'Area europea con notti tropicali', 'fr' => 'Part de l’Europe avec des nuits tropicales', 'de' => 'Europäische Fläche mit Tropennächten', 'es' => 'Área europea con noches tropicales', 'nl' => 'Europees gebied met tropische nachten', 'sv' => 'Europeisk yta med tropiska nätter', 'pl' => 'Obszar Europy z nocami tropikalnymi'],
            'chart.tropical_share.description' => ['en' => 'Share of Europe experiencing at least one tropical night in a year, by decade.', 'it' => 'Quota d’Europa che registra almeno una notte tropicale in un anno, per decennio.', 'fr' => 'Part de l’Europe connaissant au moins une nuit tropicale dans l’année, par décennie.', 'de' => 'Anteil Europas mit mindestens einer Tropennacht pro Jahr, nach Jahrzehnt.', 'es' => 'Proporción de Europa con al menos una noche tropical al año, por década.', 'nl' => 'Aandeel van Europa met minstens één tropische nacht per jaar, per decennium.', 'sv' => 'Andel av Europa med minst en tropisk natt under ett år, per årtionde.', 'pl' => 'Udział Europy z co najmniej jedną nocą tropikalną w roku, według dekady.'],
            'chart.tropical_share.reasoning' => ['en' => 'Copernicus reports approximately 20% of Europe in the 1970s, 34% in the 2010s and 35% in the 2020s experiencing at least one tropical night, defined by minimum air temperature not falling below 20°C. These are observed decadal area shares, not population exposure or UTCI.', 'it' => 'Copernicus riporta circa il 20% dell’Europa negli anni 1970, il 34% negli anni 2010 e il 35% negli anni 2020 con almeno una notte tropicale, definita da temperatura minima dell’aria non inferiore a 20°C. Sono quote areali decennali osservate, non esposizione della popolazione né UTCI.', 'fr' => 'Copernicus indique environ 20% de l’Europe dans les années 1970, 34% dans les années 2010 et 35% dans les années 2020 avec au moins une nuit tropicale, définie par une température minimale de l’air ne descendant pas sous 20°C. Il s’agit de parts de superficie observées, non d’exposition de population ni d’UTCI.', 'de' => 'Copernicus meldet etwa 20% Europas in den 1970ern, 34% in den 2010ern und 35% in den 2020ern mit mindestens einer Tropennacht, definiert als minimale Lufttemperatur nicht unter 20°C. Es sind beobachtete Flächenanteile nach Jahrzehnten, keine Bevölkerungsexposition oder UTCI.', 'es' => 'Copernicus informa de aproximadamente 20% de Europa en los años 1970, 34% en los 2010 y 35% en los 2020 con al menos una noche tropical, definida por una temperatura mínima del aire que no baja de 20°C. Son proporciones de área observadas por década, no exposición de población ni UTCI.', 'nl' => 'Copernicus meldt ongeveer 20% van Europa in de jaren 1970, 34% in de jaren 2010 en 35% in de jaren 2020 met minstens één tropische nacht, gedefinieerd als minimale luchttemperatuur niet onder 20°C. Dit zijn waargenomen gebiedsaandelen per decennium, geen bevolkingsblootstelling of UTCI.', 'sv' => 'Copernicus rapporterar cirka 20% av Europa på 1970-talet, 34% på 2010-talet och 35% på 2020-talet med minst en tropisk natt, definierad som att minsta lufttemperaturen inte sjunker under 20°C. Det är observerade ytelar per årtionde, inte befolkningsexponering eller UTCI.', 'pl' => 'Copernicus podaje około 20% Europy w latach 70., 34% w latach 2010. i 35% w latach 2020. z co najmniej jedną nocą tropikalną, zdefiniowaną jako minimalna temperatura powietrza nie niższa niż 20°C. Są to obserwowane udziały powierzchni, nie ekspozycja ludności ani UTCI.'],
            'chart.stress_days.title' => ['en' => 'Strong heat-stress days in southeastern Europe', 'it' => 'Giorni di forte stress termico nell’Europa sudorientale', 'fr' => 'Jours de fort stress thermique en Europe du Sud-Est', 'de' => 'Tage mit starkem Hitzestress in Südosteuropa', 'es' => 'Días de fuerte estrés térmico en el sudeste de Europa', 'nl' => 'Dagen met sterke hittestress in Zuidoost-Europa', 'sv' => 'Dagar med stark värmestress i sydöstra Europa', 'pl' => 'Dni silnego stresu cieplnego w Europie Południowo-Wschodniej'],
            'chart.stress_days.description' => ['en' => 'Summer days with UTCI at or above 32°C compared with the 1991–2020 average.', 'it' => 'Giorni estivi con UTCI pari o superiore a 32°C rispetto alla media 1991–2020.', 'fr' => 'Jours d’été avec UTCI supérieur ou égal à 32°C comparés à la moyenne 1991–2020.', 'de' => 'Sommertage mit UTCI ab 32°C im Vergleich zum Mittel 1991–2020.', 'es' => 'Días de verano con UTCI igual o superior a 32°C frente a la media 1991–2020.', 'nl' => 'Zomerdagen met UTCI vanaf 32°C vergeleken met het gemiddelde 1991–2020.', 'sv' => 'Sommardagar med UTCI på minst 32°C jämfört med medelvärdet 1991–2020.', 'pl' => 'Dni letnie z UTCI co najmniej 32°C w porównaniu ze średnią 1991–2020.'],
            'chart.stress_days.reasoning' => ['en' => 'Copernicus observed 66 summer days in southeastern Europe with at least strong heat stress in 2024, compared with a 1991–2020 average of 29. Strong heat stress is the UTCI category from 32°C to below 38°C; UTCI is a thermal-comfort index and is not air temperature.', 'it' => 'Copernicus ha osservato 66 giorni estivi con almeno forte stress termico nell’Europa sudorientale nel 2024, contro una media 1991–2020 di 29. Il forte stress termico è la categoria UTCI da 32°C a meno di 38°C; l’UTCI è un indice di comfort termico e non la temperatura dell’aria.', 'fr' => 'Copernicus a observé 66 jours d’été avec au moins un fort stress thermique en Europe du Sud-Est en 2024, contre une moyenne 1991–2020 de 29. Le fort stress correspond à l’UTCI de 32°C à moins de 38°C ; l’UTCI est un indice de confort thermique, pas la température de l’air.', 'de' => 'Copernicus beobachtete 2024 in Südosteuropa 66 Sommertage mit mindestens starkem Hitzestress gegenüber einem Mittel 1991–2020 von 29. Starker Hitzestress ist die UTCI-Kategorie von 32°C bis unter 38°C; UTCI ist ein thermischer Komfortindex und keine Lufttemperatur.', 'es' => 'Copernicus observó 66 días de verano con al menos fuerte estrés térmico en el sudeste de Europa en 2024, frente a una media 1991–2020 de 29. El fuerte estrés es la categoría UTCI de 32°C a menos de 38°C; UTCI es un índice de confort térmico, no temperatura del aire.', 'nl' => 'Copernicus zag in 2024 66 zomerdagen met minstens sterke hittestress in Zuidoost-Europa, tegenover gemiddeld 29 in 1991–2020. Sterke hittestress is de UTCI-categorie van 32°C tot onder 38°C; UTCI is een thermische comfortindex en geen luchttemperatuur.', 'sv' => 'Copernicus observerade 66 sommardagar med minst stark värmestress i sydöstra Europa 2024, jämfört med medelvärdet 29 för 1991–2020. Stark värmestress är UTCI-kategorin 32°C till under 38°C; UTCI är ett termiskt komfortindex, inte lufttemperatur.', 'pl' => 'Copernicus zaobserwował 66 letnich dni z co najmniej silnym stresem cieplnym w Europie Południowo-Wschodniej w 2024 r., wobec średniej 29 z lat 1991–2020. Silny stres to kategoria UTCI od 32°C do poniżej 38°C; UTCI jest wskaźnikiem komfortu cieplnego, nie temperaturą powietrza.'],
            'chart.nights.title' => ['en' => 'Tropical nights in southeastern Europe', 'it' => 'Notti tropicali nell’Europa sudorientale', 'fr' => 'Nuits tropicales en Europe du Sud-Est', 'de' => 'Tropennächte in Südosteuropa', 'es' => 'Noches tropicales en el sudeste de Europa', 'nl' => 'Tropische nachten in Zuidoost-Europa', 'sv' => 'Tropiska nätter i sydöstra Europa', 'pl' => 'Noce tropikalne w Europie Południowo-Wschodniej'],
            'chart.nights.description' => ['en' => 'Summer nights with minimum air temperature at or above 20°C.', 'it' => 'Notti estive con temperatura minima dell’aria pari o superiore a 20°C.', 'fr' => 'Nuits d’été avec une température minimale de l’air supérieure ou égale à 20°C.', 'de' => 'Sommernächte mit minimaler Lufttemperatur ab 20°C.', 'es' => 'Noches de verano con temperatura mínima del aire igual o superior a 20°C.', 'nl' => 'Zomernachten met een minimale luchttemperatuur van minstens 20°C.', 'sv' => 'Sommarnätter med lägsta lufttemperatur på minst 20°C.', 'pl' => 'Letnie noce z minimalną temperaturą powietrza co najmniej 20°C.'],
            'chart.nights.reasoning' => ['en' => 'Copernicus reports a long-term average of 8 tropical nights, the prior record of 16 in 2012 and 23 in summer 2024 for southeastern Europe. Values are observed counts using the same minimum-air-temperature threshold of 20°C; they are not UTCI or heat-index measurements.', 'it' => 'Copernicus riporta una media di lungo periodo di 8 notti tropicali, il precedente record di 16 nel 2012 e 23 nell’estate 2024 per l’Europa sudorientale. Sono conteggi osservati con la stessa soglia di temperatura minima dell’aria di 20°C; non sono misure UTCI o heat index.', 'fr' => 'Copernicus indique une moyenne de long terme de 8 nuits tropicales, le précédent record de 16 en 2012 et 23 durant l’été 2024 en Europe du Sud-Est. Ce sont des comptes observés avec le même seuil de température minimale de l’air de 20°C, et non des mesures UTCI ou d’indice de chaleur.', 'de' => 'Copernicus nennt einen langjährigen Mittelwert von 8 Tropennächten, den bisherigen Rekord von 16 im Jahr 2012 und 23 im Sommer 2024 für Südosteuropa. Es sind beobachtete Zählwerte mit derselben Mindestlufttemperatur von 20°C, keine UTCI- oder Hitzeindexmessungen.', 'es' => 'Copernicus informa de una media a largo plazo de 8 noches tropicales, el récord anterior de 16 en 2012 y 23 en el verano de 2024 en el sudeste de Europa. Son recuentos observados con el mismo umbral de temperatura mínima del aire de 20°C, no mediciones UTCI o de índice de calor.', 'nl' => 'Copernicus meldt een langjarig gemiddelde van 8 tropische nachten, het vorige record van 16 in 2012 en 23 in zomer 2024 voor Zuidoost-Europa. Dit zijn waargenomen aantallen met dezelfde minimumluchttemperatuurdrempel van 20°C, geen UTCI- of hitte-indexmetingen.', 'sv' => 'Copernicus rapporterar ett långtidsmedel på 8 tropiska nätter, det tidigare rekordet 16 år 2012 och 23 sommaren 2024 i sydöstra Europa. Det är observerade antal med samma minsta lufttemperaturtröskel 20°C, inte UTCI- eller värmeindexmått.', 'pl' => 'Copernicus podaje długoterminową średnią 8 nocy tropikalnych, poprzedni rekord 16 w 2012 r. i 23 latem 2024 r. w Europie Południowo-Wschodniej. Są to obserwowane liczby przy tym samym progu minimalnej temperatury powietrza 20°C, nie pomiary UTCI ani indeksu ciepła.'],
            'chart.cdd.title' => ['en' => 'Cooling degree days in 2022', 'it' => 'Gradi giorno di raffrescamento nel 2022', 'fr' => 'Degrés-jours de refroidissement en 2022', 'de' => 'Kühlgradtage 2022', 'es' => 'Grados-día de refrigeración en 2022', 'nl' => 'Koelgraaddagen in 2022', 'sv' => 'Kylgraddagar 2022', 'pl' => 'Stopniodni chłodzenia w 2022 r.'],
            'chart.cdd.description' => ['en' => 'Eurostat cooling degree days for five high-demand EU countries.', 'it' => 'Gradi giorno di raffrescamento Eurostat per cinque paesi UE ad alta domanda.', 'fr' => 'Degrés-jours de refroidissement Eurostat pour cinq pays de l’UE à forte demande.', 'de' => 'Eurostat-Kühlgradtage für fünf EU-Länder mit hoher Nachfrage.', 'es' => 'Grados-día de refrigeración de Eurostat para cinco países de la UE con alta demanda.', 'nl' => 'Eurostat-koelgraaddagen voor vijf EU-landen met hoge vraag.', 'sv' => 'Eurostats kylgraddagar för fem EU-länder med hög efterfrågan.', 'pl' => 'Stopniodni chłodzenia Eurostatu dla pięciu krajów UE o wysokim zapotrzebowaniu.'],
            'chart.cdd.reasoning' => ['en' => 'The 2022 values are direct Eurostat national cooling-degree-day observations: Malta 842, Cyprus 698, Spain 384, Italy 375 and Greece 372. CDD is a weather-derived energy-demand indicator, not a temperature reading or forecast; all bars use the same Eurostat definition and year.', 'it' => 'I valori 2022 sono osservazioni nazionali dirette Eurostat dei gradi giorno di raffrescamento: Malta 842, Cipro 698, Spagna 384, Italia 375 e Grecia 372. I CDD sono un indicatore meteorologico della domanda energetica, non una temperatura o previsione; tutte le barre usano la stessa definizione e lo stesso anno Eurostat.', 'fr' => 'Les valeurs 2022 sont des observations nationales directes Eurostat de degrés-jours de refroidissement : Malte 842, Chypre 698, Espagne 384, Italie 375 et Grèce 372. Le CDD est un indicateur météorologique de demande énergétique, non une température ni une prévision ; toutes les barres utilisent la même définition et la même année Eurostat.', 'de' => 'Die Werte 2022 sind direkte nationale Eurostat-Beobachtungen von Kühlgradtagen: Malta 842, Zypern 698, Spanien 384, Italien 375 und Griechenland 372. CDD ist ein wetterbasierter Energiebedarfsindikator, keine Temperatur oder Prognose; alle Balken verwenden dieselbe Eurostat-Definition und dasselbe Jahr.', 'es' => 'Los valores de 2022 son observaciones nacionales directas de Eurostat de grados-día de refrigeración: Malta 842, Chipre 698, España 384, Italia 375 y Grecia 372. CDD es un indicador meteorológico de demanda energética, no una temperatura ni previsión; todas las barras usan la misma definición y año de Eurostat.', 'nl' => 'De waarden voor 2022 zijn directe nationale Eurostat-waarnemingen van koelgraaddagen: Malta 842, Cyprus 698, Spanje 384, Italië 375 en Griekenland 372. CDD is een weerafgeleide indicator voor energievraag, geen temperatuur of voorspelling; alle balken gebruiken dezelfde Eurostat-definitie en hetzelfde jaar.', 'sv' => 'Värdena 2022 är direkta nationella Eurostat-observationer av kylgraddagar: Malta 842, Cypern 698, Spanien 384, Italien 375 och Grekland 372. CDD är en väderbaserad indikator för energibehov, inte temperatur eller prognos; alla staplar använder samma Eurostat-definition och år.', 'pl' => 'Wartości z 2022 r. to bezpośrednie krajowe obserwacje Eurostatu dotyczące stopniodni chłodzenia: Malta 842, Cypr 698, Hiszpania 384, Włochy 375 i Grecja 372. CDD jest pogodowym wskaźnikiem zapotrzebowania na energię, nie temperaturą ani prognozą; wszystkie słupki używają tej samej definicji i roku Eurostatu.'],
        ];

        if (! isset($texts[$key])) {
            throw new InvalidArgumentException('Unknown Unlivable Heat translation key: '.$key);
        }

        return $texts[$key];
    }

    /** @return array{en: array<int, string>, it: array<int, string>, fr: array<int, string>, de: array<int, string>, es: array<int, string>, nl: array<int, string>, sv: array<int, string>, pl: array<int, string>} */
    public function list(string $key): array
    {
        $lists = [
